import{_ as e,o as a,c as r,U as t}from"./chunks/framework.8ac43607.js";const _=JSON.parse('{"title":"Web3","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/33.web3/02.web3/index.md","filePath":"tutorials/33.web3/02.web3/index.md","lastUpdated":1689907217000}'),o={name:"tutorials/33.web3/02.web3/index.md"},b=t('<h1 id="web3" tabindex="-1">Web3 <a class="header-anchor" href="#web3" aria-label="Permalink to &quot;Web3&quot;">​</a></h1><p>在解释 Web3 概念之前，我们先来了解 Web1 和 Web2。</p><h2 id="web1-1990-2004-可读" tabindex="-1">Web1 (1990 - 2004，可读) <a class="header-anchor" href="#web1-1990-2004-可读" aria-label="Permalink to &quot;Web1 (1990 - 2004，可读)&quot;">​</a></h2><p>Web1 是指互联网的第一阶段，公司拥有静态网站，网站为用户提供在线内容和信息，用户之间几乎不能互动，用户也很少创造内容。</p><p><img src="https://ethereum.org/static/aabd6f7a956dd8a7038185b2d03b8459/00d43/web1.png" alt="Web1"></p><p><a href="https://ethereum.org/zh/web3/" target="_blank" rel="noreferrer">图源</a></p><h2 id="web2-2004-至今-可读可写" tabindex="-1">Web2 (2004 至今，可读可写) <a class="header-anchor" href="#web2-2004-至今-可读可写" aria-label="Permalink to &quot;Web2 (2004 至今，可读可写)&quot;">​</a></h2><p>随着社交媒体平台的出现，Web 2 时期于 2004 年开启，这也是我们大多数人今天所熟悉和使用的互联网。</p><p>互联网公司除了向用户提供内容外，还开始提供平台来共享用户生产的内容，并参与用户间的交互，因此越来越多的人参与到互联网中来。广告驱动的盈利模式也顺势出现，虽然用户可以创作内容，但他们并不拥有内容或通过将内容变现来获益。</p><p>对应地，互联网很大程度上被 Apple、Amazon、Meta、Google 等互联网巨头所掌控，属于 <strong>中心化网络 centralized network</strong>。</p><p>尽管 Web2 提高了用户体验，但也存在大量问题。</p><ol><li>数据泄漏和篡改问题，影响个人数据安全和隐私</li><li>互联网公司审查和操控创作内容问题</li><li>严重依赖第三方（互联网公司）或其提供的平台，上游问题严重影响下游消费者，如 AWS 瘫痪会影响大部分互联网，平台政策强迫离开等</li></ol><p><img src="https://ethereum.org/static/9f443e1757f9bdec73836ab7ff1e2e61/6acbf/web2.png" alt="Web2"></p><p><a href="https://ethereum.org/zh/web3/" target="_blank" rel="noreferrer">图源</a></p><h2 id="web3-可读可写可拥有" tabindex="-1">Web3（可读可写可拥有） <a class="header-anchor" href="#web3-可读可写可拥有" aria-label="Permalink to &quot;Web3（可读可写可拥有）&quot;">​</a></h2><p>正如教程开头提到的，Web3 代表了一个新的、更好的互联网愿景。它是 <strong>去中心化网络 decentralized network</strong>，在线共享，集体管理，没有互联网公司把控。</p><p>通过去中心化、分布式、无需许可、支持原生支付、无需依赖可信第三方而通过激励措施和经济机制运转等，Web3 增强了我们今天所了解的网络。目前，Web3 已经得到了广泛的应用，比如加密货币、智能合约、金融、游戏、供应链追踪、防伪保护、资产所有权验证等。</p><p>不可否认的是，Web3 也有着它的局限性。比如交易成本较高，用户体验不佳，基础设施仍未完善等。</p><p>在可见的将来，Web3 仍会不断发展，我们可以期待一个更好的互联网。</p><p><img src="https://ethereum.org/static/9874c3dff5f2a382464e4fec02c2d78a/6acbf/web3.png" alt="Web3"></p><p><a href="https://ethereum.org/zh/web3/" target="_blank" rel="noreferrer">图源</a></p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://ethereum.org/zh/web3/" target="_blank" rel="noreferrer">以太坊 - Web3 简介</a></li><li><a href="https://learnweb3.io/degrees/ethereum-developer-degree/freshman/what-is-web3/" target="_blank" rel="noreferrer">LearnWeb3 - What is Web3</a></li><li><a href="https://ethereum.org/zh/developers/docs/intro-to-ethereum/" target="_blank" rel="noreferrer">以太坊 - 以太坊简介</a></li></ul>',23),l=[b];function n(h,i,p,s,d,c){return a(),r("div",null,l)}const u=e(o,[["render",n]]);export{_ as __pageData,u as default};
